{
  "name": "system-spec-harness",
  "version": "0.1.0",
  "description": "カテゴリ×プラットフォームの網羅マトリクス、公式出典、独立完成度評価を用いてシステム仕様書を生成するハーネス plugin。",
  "author": {
    "name": "harness maintainers"
  },
  "hooks": "./hooks/hooks.json"
}

{
  "$schema": "../../harness-creator/skills/ref-pkg-contract/schemas/package-contract.schema.json",
  "package_mode": "bundle",
  "plugin_name": "system-spec-harness",
  "entry_points": {
    "skills": [
      "run-system-spec-elicit",
      "run-system-spec-doc-fetch",
      "run-system-spec-compile",
      "ref-system-design-knowledge",
      "assign-system-spec-completeness-evaluator"
    ],
    "agents": [
      "system-spec-hearing-auditor",
      "system-spec-matrix-auditor",
      "system-spec-doc-freshness-auditor"
    ],
    "commands": [
      "spec-hearing-start",
      "spec-compile"
    ],
    "hooks": [
      "guard-confirmed-chapter-overwrite",
      "record-audit-fork"
    ]
  },
  "distribution": {
    "distributable": true,
    "bundle_targets": [
      "skills-full"
    ],
    "category": "productivity",
    "tags": [
      "spec",
      "hearing",
      "system-design"
    ]
  },
  "depends_on": [],
  "pkg_checks": {}
}

