    "essential_purpose": "自分の TODO を、いかなる外部サービスにもデータを渡さずに、手元の 1 プロセスだけで管理・自動化できる状態にする。",
    "background": "既存の SaaS 型 TODO 管理はデータが外部に保管され、オフラインでは使えず、スクリプトからの自動操作にも制約がある。API として手元に持てれば、自作クライアントや shell script から自由に組み合わせられる。",
    "goals": [
      {
        "id": "G1",
        "text": "TODO データが端末外へ出ない (外部 network 送信 0 件)"
      },
      {
        "id": "G2",
        "text": "認証された利用者だけが自分の TODO を作成・参照・更新・削除できる"
      },
      {
        "id": "G3",
        "text": "プロセス再起動後も TODO が失われない"
      },
      {
        "id": "G4",
        "text": "追加の常駐ミドルウェアなしに 1 コマンドで起動・停止・バックアップできる"
      }
    ],
    "objectives": [
      {
        "id": "O1",
        "text": "実装依存の外向き通信を 0 にし、依存パッケージも起動時に network を張らないものだけにする。",
        "measure": "外向き通信 0 件"
      },
      {
        "id": "O2",
        "text": "すべての TODO エンドポイントを認証必須にし、未認証要求は 401 を返す。",
        "measure": "未認証要求全 401"
      },
      {
        "id": "O3",
        "text": "永続化先を単一ファイルにし、再起動後の一覧取得で登録済み TODO が全件戻る。",
        "measure": "再起動後全件復帰"
      },
      {
        "id": "O4",
        "text": "起動は 1 コマンド、バックアップはデータファイル 1 個のコピーで完了する。",
        "measure": "1 コマンド起動・1 ファイルバックアップ"
      }
    ],
    "success_criteria": [
      "受入テストで、未認証要求が全 TODO エンドポイントで 401 になる。",
      "受入テストで、作成→プロセス再起動→一覧取得を行い、作成した TODO が戻る。",
      "依存関係と実装に外部 host への送信処理が 0 件であることをレビューで確認する。",
      "起動手順が 1 コマンド、バックアップ手順が 1 ファイルコピーで記述できる。"
    ],
    "stakeholders": [
      "利用者兼開発者 (本人): 唯一の利用者であり、要求の確定権限を持つ。",
      "運用者 (本人): 起動・停止・バックアップを行う。第三者運用は想定しない。"
    ],
    "scope": {
      "in": [
        "認証",
        "TODO の CRUD",
        "SQLite 永続化",
        "localhost での HTTP 提供",
        "起動/バックアップ手順"
      ],
      "out": [
        "GUI クライアント実装",
        "複数ユーザー間の共有",
        "外部同期",
        "クラウド配備",
        "通知機能"
      ]
    },
    "constraints": [
      "外部 network への送信を実装に含めない (実行時の外向き通信 0)。",
      "常駐ミドルウェア (別プロセスの DB サーバー等) を増やさない。",
      "費用は 0 円 (無料・OSS のみ)。",
      "単一プロセス・単一データファイルで完結させる。"
    ],
    "concrete_intents": [
      {
        "id": "I1",
        "text": "TODO の作成・一覧・単体取得・更新・完了・削除。",
        "serves": [
          "G2",
          "G3"
        ]
      },
      {
        "id": "I2",
        "text": "単一利用者向けの token 認証。",
        "serves": [
          "G2"
        ]
      },
      {
        "id": "I3",
        "text": "SQLite ファイルへの永続化とスキーマ初期化。",
        "serves": [
          "G1",
          "G3",
          "G4"
        ]
      },
      {
        "id": "I4",
        "text": "localhost バインドでの HTTP 提供と OpenAPI 定義の提供。",
        "serves": [
          "G1",
          "G4"
        ]
      }
    ],
    "confirmed": true,
    "approval_ref": "approval_001"
  },
